INSERT INTO property_list (type, city, price, no_bedrooms, no_bathrooms, size, furniture, summary, owner_id, date_listed, detail)
VALUES
('Apartment', 'Manchester', 980, 2, 1, 70, 'Furnished', 'A modern two-bedroom apartment located close to Manchester city centre, offering excellent access to shops, restaurants, and transport links. The property features a bright open-plan living area, a fully equipped kitchen, and comfortable bedrooms, making it ideal for professionals or small families seeking convenience and comfort.', 1, '2026-03-01', 'This two-bedroom apartment is an excellent opportunity in Manchester''s competitive rental market, where city-centre apartments remain in high demand among graduates and young professionals. At £980 pcm, it sits competitively below the city-centre average, offering strong value in a market where private rents rose to an average of £1,345 in early 2026. The furnished specification removes the burden of upfront furniture costs, making it immediately move-in ready. The open-plan living area maximises the 70 sq metre footprint, creating a sociable and flexible living space. Its proximity to the city centre means residents benefit from Manchester''s thriving restaurant scene, retail districts, and extensive Metrolink and bus connections, making car-free living entirely practical. Ideal for professional sharers or a couple.'),
('Terraced', 'Manchester', 1100, 3, 1, 85, 'Unfurnished', 'This well-maintained terraced house in Manchester provides generous living space with three bedrooms, a cosy lounge, and a functional kitchen. Situated in a quiet residential area with good access to local amenities and transport, it is well suited for families looking for a comfortable and practical home.', 2, '2026-03-02', 'Terraced houses are among the most sought-after property types in Manchester, with rental values rising around 3.3% over the past year, reflecting sustained family demand. This three-bedroom example at £1,100 pcm offers excellent value for money, particularly given its 85 sq metre floor area and quiet residential setting. Unfurnished, it allows tenants to personalise the space entirely to their own tastes and bring existing furniture, which many long-term family renters prefer. The cosy lounge provides a distinct reception room separate from the kitchen, a layout well-suited to family life. Good transport links mean commuting into Manchester city centre or to surrounding employment hubs is straightforward. With three bedrooms, the property comfortably accommodates a family or professional sharers, and access to local amenities including shops and schools adds significant day-to-day convenience.'),
('Detached', 'Manchester', 1800, 4, 3, 150, 'Semi-Furnished', 'A spacious detached property in Manchester offering four bedrooms, multiple bathrooms, and large living areas. The home includes a private garden and driveway, making it ideal for families. Located in a desirable neighbourhood close to schools and amenities, it offers both comfort and convenience.', 3, '2026-03-03', 'This substantial four-bedroom detached home represents the premium end of the Manchester rental market, and at £1,800 pcm it reflects the considerable space and lifestyle benefits on offer. With 150 sq metres of living space, three bathrooms, and a private garden and driveway, it caters to larger families who require room to grow and space to entertain. Semi-furnished means key fixtures and fittings are in place, reducing setup costs while still allowing tenants to add personal touches. Detached properties in Manchester offer the highest levels of privacy, with no shared walls and independent outdoor space — increasingly valued by tenants post-pandemic. Proximity to well-regarded local schools makes this particularly attractive to families with children. Manchester''s property market continues to see strong demand for family homes, with detached house values appreciating steadily, making this a stable and desirable long-term rental option.'),
('Bungalow', 'Manchester', 1200, 2, 1, 80, 'Furnished', 'This charming bungalow in Manchester offers comfortable single-level living with two bedrooms, a bright lounge, and a well-equipped kitchen. The property benefits from a private garden and off-street parking, making it ideal for those seeking a quieter lifestyle while staying close to the city.', 1, '2026-03-04', 'Bungalows are a comparatively rare property type in Manchester''s rental market, making this a distinctive and desirable listing. Single-level living is particularly appealing to older tenants, those with mobility considerations, or anyone simply preferring the ease and accessibility of a layout without stairs. At £1,200 pcm for a furnished two-bedroom property with 80 sq metres of space, a private garden, and off-street parking, it offers strong value relative to equivalently sized terraced or semi-detached rentals. The furnished specification makes it immediately habitable, and the well-equipped kitchen removes the need for appliance purchases. The private garden provides outdoor space for relaxation or gardening, while off-street parking — increasingly scarce closer to the city centre — adds meaningful practical value. Its location allows residents to enjoy a quieter pace of life without sacrificing access to Manchester''s amenities and transport network.'),
('Semi-Detached', 'Manchester', 1400, 3, 2, 105, 'Unfurnished', 'A well-presented semi-detached home in Manchester featuring three bedrooms, two bathrooms, and spacious living areas. The property includes a private garden and driveway, providing a great environment for families. Conveniently located near schools, shops, and transport links for easy commuting.', 2, '2026-03-05', 'Semi-detached houses are currently the strongest-performing property type in the Manchester market, with values rising approximately 3.8% over the past year driven by persistent family demand and limited supply in desirable school catchments. This three-bedroom example at £1,400 pcm offers a compelling package: two bathrooms eliminate the morning bottleneck common in family homes with a single bathroom, while the 105 sq metre footprint delivers genuinely spacious living. The private garden provides safe outdoor play space for children and room for outdoor dining, while the driveway offers off-street parking. Being unfurnished suits families and long-term tenants who have their own belongings and wish to make the property feel like home. Convenient access to schools, shops, and transport links makes day-to-day living highly practical. Manchester''s ongoing regeneration and strong rental demand mean well-located semi-detached homes like this are consistently in high demand and let quickly.'),
('Apartment', 'London', 2000, 2, 1, 65, 'Furnished', 'A modern apartment in central London offering two bedrooms, a bright living space, and a fully fitted kitchen. Located close to major transport links, shops, and restaurants, this property is perfect for professionals seeking a vibrant and convenient city lifestyle.', 2, '2026-03-11', 'This two-bedroom furnished apartment sits at £2,000 pcm, competitive for central London where demand from professionals and graduates remains strong despite a modest easing of the market in early 2026. Furnished rentals in central London command a notable premium — typically 10 to 15% above equivalent unfurnished stock — making this a well-positioned listing for tenants who want a move-in-ready home without the hassle of sourcing furniture. At 65 sq metres, the layout is efficient and well-suited to a couple or two professional sharers. London''s rental vacancy rate sits at approximately 2% in 2026, one of the tightest in the UK, meaning well-priced properties in accessible locations let quickly — typically within 15 to 30 days. Proximity to major transport links is a significant draw, as tube and rail access can command a premium of up to £300 pcm in some central zones. Ideal for professionals working in the city''s finance, tech, or creative sectors.'),
('Terraced', 'London', 2300, 3, 2, 90, 'Semi-Furnished', 'This attractive terraced house in London features three bedrooms, two bathrooms, and spacious living areas. Combining traditional character with modern features, the property is located near excellent transport links, making it ideal for families or professionals working in the city.', 3, '2026-03-12', 'Terraced houses occupy a distinctive and highly desirable niche in the London rental market, offering the character of period architecture alongside practical family living. This three-bedroom, two-bathroom example at £2,300 pcm provides 90 sq metres of space — a generous footprint by London standards — with the added benefit of a semi-furnished specification that bridges the gap between a blank canvas and a fully equipped home. Two bathrooms are a particularly valued feature for sharers or families, removing the daily bottleneck of a single facility. London rents are projected to grow by 2 to 3% through 2026, meaning this listing is entering the market at a stable and well-timed point. Transport connectivity is a key driver of rental value in the capital, and proximity to strong links supports longer tenancy durations and lower void risk. The combination of traditional charm and modern updates appeals to a broad tenant pool, from young professional sharers to families relocating to London.'),
('Detached', 'London', 3500, 5, 3, 180, 'Unfurnished', 'A large detached home in London offering five bedrooms, multiple bathrooms, and extensive living space. The property includes a private garden and driveway, providing a rare opportunity for spacious family living in the capital while remaining close to key amenities.', 1, '2026-03-13', 'Detached homes of this scale are genuinely rare within Greater London, making this five-bedroom property a standout listing in a market where space is consistently at a premium. At £3,500 pcm and 180 sq metres, it offers one of the most competitive cost-per-square-metre ratios available for a detached home in the capital. Three bathrooms comfortably serve a large family, and the private garden and driveway — both increasingly scarce commodities in London — add significant lifestyle value. Unfurnished, it suits families intending a long-term tenancy who wish to bring their own belongings and personalise the space. London''s rental supply remains 23% below pre-pandemic levels according to Zoopla''s March 2026 report, meaning large family homes like this face limited competition and tend to attract committed, long-staying tenants. Proximity to key amenities further enhances day-to-day convenience and supports the strong overall appeal of this exceptional London family home.'),
('Bungalow', 'London', 2100, 2, 1, 85, 'Furnished', 'A rare bungalow in London offering comfortable single-level living with two bedrooms, a bright lounge, and a modern kitchen. The property includes a private garden, providing a peaceful retreat within the city and easy access to local amenities and transport links.', 2, '2026-03-14', 'Bungalows are exceptionally uncommon in London''s rental market, where the premium placed on land means single-storey homes represent a genuinely rare find. This two-bedroom example at £2,100 pcm offers something the vast majority of London rentals cannot: step-free, single-level living combined with a private garden — a combination that makes it particularly attractive to older tenants, those with mobility requirements, or anyone seeking a calmer pace of life without leaving the city. At 85 sq metres it is spacious for the price point, and the furnished specification means tenants can move in without delay or additional expense. The private garden provides outdoor space that is highly sought after in a city where outdoor areas command a significant premium. London''s overall vacancy rate of around 2% in early 2026 means well-differentiated properties like this — offering something genuinely distinct from the standard apartment stock — attract strong and immediate interest. Easy access to local amenities and transport links ensures residents remain well-connected to the wider city.'),
('Semi-Detached', 'London', 2700, 4, 2, 120, 'Semi-Furnished', 'A spacious semi-detached home in London featuring four bedrooms, modern interiors, and generous living space. Located in a desirable neighbourhood close to schools, transport, and amenities, it is ideal for families.', 3, '2026-03-15', 'Four-bedroom semi-detached homes are among the most practically versatile properties in the London rental market, equally suited to growing families and groups of professional sharers. At £2,700 pcm, this 120 sq metre home offers a strong value proposition in a city where space is consistently scarce and family housing in desirable school catchments commands a premium. The semi-furnished specification provides a practical baseline of key fixtures while leaving room for tenants to personalise the interior. Two bathrooms significantly reduce household friction, a feature that becomes especially important in a four-bedroom home. London''s five-year residential rent forecasts project growth of over 19% between 2024 and 2028, meaning securing a well-priced family home now offers tenants a degree of stability in an otherwise rising market. Proximity to schools is a decisive factor for family tenants, and strong transport links support easy commuting across the city. This property ticks all the key boxes that London family renters prioritise.'),
('Apartment', 'Birmingham', 900, 2, 1, 65, 'Furnished', 'A modern apartment in Birmingham offering two bedrooms, a bright living area, and a fully fitted kitchen. Located close to the city centre, the property provides easy access to shops and transport.', 3, '2026-03-21', 'This two-bedroom furnished apartment at £900 pcm represents outstanding value in Birmingham''s rental market, where the citywide average rent reached £1,087 in January 2026. Sitting well below that average, it offers a compelling entry point for young professionals and graduates who make up the largest share of Birmingham''s renter demographic. Apartments in Birmingham consistently deliver the strongest rental yields of any property type, often exceeding 7% in core city districts such as Digbeth and the Jewellery Quarter, reflecting the intense demand from the city''s expanding professional population. The furnished specification removes upfront costs for tenants and ensures the property is immediately habitable. Birmingham rents rose 4.3% in the year to January 2026, and JLL projects rental values will grow by approximately 18.8% between 2025 and 2029 — the second-highest forecast among the UK''s major cities — making this an excellent time to secure an affordable city-centre home before further increases take hold.'),
('Terraced', 'Birmingham', 950, 3, 1, 80, 'Unfurnished', 'This terraced home in Birmingham offers three bedrooms, a spacious lounge, and a practical kitchen. Situated in a well-connected area close to local amenities.', 1, '2026-03-22', 'Terraced houses are among the strongest-performing property types in Birmingham''s rental market, with rents for this category rising 4.8% in the year to January 2026 — the highest rate of growth of any property type in the city. At £950 pcm for a three-bedroom, 80 sq metre home, this listing offers exceptional value against the citywide average rent of £1,087. The unfurnished layout suits long-term tenants such as families and professional sharers who prefer to bring their own belongings and settle in for an extended stay. A spacious lounge provides a distinct and comfortable reception room, ideal for family life or relaxing after work. Birmingham''s regeneration pipeline — including major projects at Smithfield and Digbeth — is driving sustained population growth and rental demand across the city. Well-connected locations with easy access to amenities and public transport are consistently among the fastest-letting properties, making this a practical and attractive choice for a wide range of renters.'),
('Detached', 'Birmingham', 1700, 4, 2, 140, 'Semi-Furnished', 'A spacious detached house in Birmingham featuring four bedrooms, a modern kitchen, and large living areas. The property includes a private garden and driveway.', 2, '2026-03-23', 'Large detached homes of this calibre are relatively uncommon in Birmingham''s rental market, where the majority of available stock consists of apartments and terraced houses. This four-bedroom, two-bathroom property at £1,700 pcm offers 140 sq metres of living space, a private garden, and a driveway — features that are highly sought after by families seeking a long-term base in the city. At roughly 56% above Birmingham''s citywide average rent, it is well-positioned given the scale and specification on offer. The semi-furnished specification provides key appliances and fixtures while allowing tenants to personalise the interior. Detached property values in Birmingham rose 3.2% in the year to January 2026, reflecting steady underlying demand. Birmingham''s salary-to-house-price ratio of just 3.63 — compared to 7.68 in London — underlines the relative affordability of the city, making it an increasingly popular destination for families relocating from the capital or other high-cost areas.'),
('Bungalow', 'Birmingham', 1100, 2, 1, 78, 'Furnished', 'A cosy bungalow in Birmingham offering two bedrooms and comfortable living space. The property includes a private garden and is located in a quiet residential area.', 3, '2026-03-24', 'Bungalows are a scarce and highly distinctive property type in Birmingham''s rental market, where the overwhelming majority of available stock consists of multi-storey houses and apartment buildings. This two-bedroom example at £1,100 pcm offers something genuinely rare: step-free, single-level living with a private garden in a quiet residential setting. These features make it especially appealing to older tenants, those with limited mobility, or anyone who simply values the ease and accessibility of a ground-floor layout. At 78 sq metres the property is comfortably proportioned, and the furnished specification means tenants can move in immediately without additional expenditure. The private garden provides outdoor space that is particularly prized in an urban environment, offering room for relaxation, gardening, or outdoor dining. Birmingham''s rental demand has grown consistently, with rents rising 4.3% in the year to January 2026, and the scarcity of bungalows relative to demand means this type of property attracts strong interest and lets reliably well.'),
('Semi-Detached', 'Birmingham', 1300, 3, 2, 105, 'Unfurnished', 'A semi-detached home in Birmingham offering three bedrooms, two bathrooms, and spacious living areas. The property includes a garden and driveway.', 1, '2026-03-25', 'Semi-detached homes are one of the most consistently in-demand property types in Birmingham, particularly among families and professional sharers who prioritise space, privacy, and outdoor access. At £1,300 pcm, this three-bedroom, two-bathroom property sits comfortably above the citywide average, reflecting its generous 105 sq metre footprint, garden, and driveway. Two bathrooms are a particularly valued feature in a three-bedroom home, ensuring household routines run smoothly for multiple occupants. Semi-detached property values in Birmingham rose around 2.1% in the year to December 2025, and forecasts project further appreciation of 3 to 4% in 2026, driven by sustained family demand and limited quality housing supply. The post-pandemic preference for homes with gardens and more living space continues to support this property type above all others. Unfurnished, it is ideally suited to tenants planning a longer-term stay who wish to make the property their own — a profile that typically results in stable, low-turnover tenancies.'),
('Apartment', 'Bristol', 1400, 2, 1, 70, 'Furnished', 'A stylish apartment in Bristol city centre offering two bedrooms, a modern kitchen, and a bright living area. Close to shops and transport links.', 2, '2026-03-26', 'This two-bedroom furnished apartment at £1,400 pcm is well-positioned in Bristol''s fast-moving rental market, where the citywide average rent reached £1,893 per month as of January 2026 — 42% above the England average. At a two-bedroom average of £1,550 across Bristol, this listing sits competitively below the mean, offering strong value for a city-centre location. Bristol rents rose 7.4% in the year to January 2026, one of the highest rates of increase of any major UK city, driven by affordability constraints keeping would-be buyers renting longer and continued population growth. The furnished specification suits the young professional and graduate demographic that dominates Bristol''s city-centre tenant pool, particularly those working in the city''s thriving tech, aerospace, and financial services sectors. Being close to shops and transport links adds significant day-to-day convenience, and city-centre apartments in Bristol typically let within a matter of days given the acute demand.'),
('Terraced', 'Bristol', 1500, 3, 2, 90, 'Semi-Furnished', 'This terraced house in Bristol offers three bedrooms, two bathrooms, and a spacious living area. Located in a popular area near amenities.', 3, '2026-03-27', 'Terraced houses form the backbone of Bristol''s housing stock, accounting for roughly 30% of all residential properties in the city, with Victorian and Edwardian examples in neighbourhoods like Bedminster, Totterdown, Southville, and Horfield among the most sought-after. At £1,500 pcm, this three-bedroom example is priced below the Bristol three-bedroom average of £1,763, offering meaningful value in a high-demand segment. Rents for terraced properties and flats in Bristol rose by 7.6% in the year to February 2026, among the strongest increases of any property type in the city. The semi-furnished specification provides useful baseline fittings while giving tenants the flexibility to personalise the space — particularly appealing to families and professional sharers planning a longer-term stay. Two bathrooms is a standout feature for a three-bedroom terraced home, significantly improving daily practicality. South Bristol terraces in areas such as Totterdown and Southville have seen price growth of 11 to 15% in recent periods, reflecting the enduring appeal of this property type in the city.'),
('Detached', 'Bristol', 2200, 4, 3, 145, 'Unfurnished', 'A large detached home in Bristol offering four bedrooms, multiple bathrooms, and generous living space. Ideal for families.', 1, '2026-02-15', 'Detached homes represent just 10% of Bristol''s residential property stock, making this four-bedroom, three-bathroom listing a genuinely rare rental opportunity in the city. At £2,200 pcm and 145 sq metres, it offers an exceptional amount of space relative to the broader Bristol market, where average house prices for detached properties reach £684,000 — underlining the scale and quality typically associated with this property type. Detached property rents in Bristol rose 6.5% in the year to February 2026, reflecting sustained demand from larger families and professionals seeking premium space. Three bathrooms entirely eliminate the bottleneck that often affects family homes with shared facilities, while the generous living areas provide room for both communal family life and quieter retreat. Unfurnished, it is ideally suited to families relocating to Bristol who bring their own belongings and intend to settle for the long term. Bristol''s population is projected to grow a further 10% by 2032, maintaining strong demand pressure on large family homes.'),
('Bungalow', 'Bristol', 1600, 2, 1, 80, 'Furnished', 'A well-maintained bungalow in Bristol offering two bedrooms and a bright living area. Located in a quiet residential area.', 2, '2026-02-10', 'Single-storey bungalows are among the rarest property types in Bristol''s rental market, where the city''s predominantly Victorian and Edwardian housing stock is almost entirely multi-storey. This two-bedroom furnished example at £1,600 pcm therefore represents a distinctive and uncommon opportunity, particularly appealing to older tenants, those with mobility requirements, or anyone who values the simplicity and accessibility of step-free living. At 80 sq metres the layout is well-proportioned, and the furnished specification means the property is immediately ready to occupy without any additional outlay on furniture or appliances. A quiet residential setting provides a welcome contrast to the busy city centre while still keeping Bristol''s amenities and transport network within easy reach. With Bristol rents rising 7.4% year-on-year as of January 2026 and average rents across all property types reaching £1,893 pcm, this bungalow is priced competitively and offers a level of character and accessibility that standard rental stock simply cannot match.'),
('Semi-Detached', 'Bristol', 1750, 3, 2, 110, 'Semi-Furnished', 'A spacious semi-detached home in Bristol featuring three bedrooms and modern living areas. Close to schools and amenities.', 3, '2026-02-05', 'Semi-detached homes are the strongest-performing property type in Bristol''s current market, with values rising approximately 1.2% year-on-year against a backdrop of broadly flat overall prices — a meaningful outperformance driven by sustained family demand and the post-pandemic preference for homes with space and gardens. This three-bedroom example at £1,750 pcm offers 110 sq metres of living space and two bathrooms, delivering the kind of generous, practical layout that family tenants consistently prioritise. Semi-furnished means key fixtures are already in place, reducing the effort and cost of setting up while still allowing personalisation. Proximity to schools is one of the most significant drivers of rental demand in Bristol, with areas like Bishopston, Horfield, and Henleaze commanding consistent premiums due to their school catchment appeal. Bristol''s Temple Quarter regeneration project, which will deliver 10,000 new homes and thousands of jobs, is expected to further boost connectivity and desirability across the city, making a well-located family home like this an excellent long-term choice.'),
('Apartment', 'York', 1200, 2, 1, 65, 'Furnished', 'A modern apartment in York located near the historic city centre. The property offers two bedrooms and a bright living area.', 1, '2026-01-20', 'This two-bedroom furnished apartment at £1,200 pcm sits comfortably above York''s two-bedroom average of £1,055 while remaining well-justified given its proximity to the historic city centre — one of the most desirable and tightly contested locations in the Yorkshire rental market. York''s overall average rent reached £1,170 per month as of January 2026, rising 5.7% year-on-year, a rate above the national average that reflects the city''s chronic undersupply of good-quality rental stock relative to persistent demand. The furnished specification suits the young professional and graduate tenant profile that dominates city-centre demand, offering an immediately habitable home without the burden of furnishing costs. York''s combination of a thriving tourism economy, strong employer base, and the University of York''s large student population creates a diverse and resilient tenant pool, keeping void periods low and rental demand consistently robust throughout the year. A bright living area maximises the 65 sq metre footprint, making the space feel open and welcoming.'),
('Terraced', 'York', 1300, 3, 1, 85, 'Unfurnished', 'A charming terraced house in York offering three bedrooms and a practical layout. Located in a quiet area.', 2, '2026-01-15', 'Terraced houses account for around 36% of York''s housing stock, making them the single most prevalent property type in the city, and rental demand for this category is consistently strong. At £1,300 pcm, this three-bedroom example sits just above the York three-bedroom average of £1,246, reflecting the quality and character that well-presented terraced homes in the city command. Terraced property rents in York rose 5.7% in the year to February 2026, the strongest rate of growth of any property type locally, driven by sustained demand from families and professional sharers. Unfurnished suits tenants planning a longer stay who prefer to bring their own belongings, a profile that typically results in stable, extended tenancies and lower turnover for landlords. The quiet residential setting appeals to tenants seeking respite from the busier city-centre streets while remaining within easy reach of York''s exceptional amenities, independent shops, and transport connections, including direct rail links to Leeds and London.'),
('Detached', 'York', 2000, 4, 2, 140, 'Semi-Furnished', 'A spacious detached home in York featuring four bedrooms, large living areas, and a private garden.', 3, '2026-01-10', 'Detached homes make up 22% of York''s housing mix, a notably higher proportion than in many comparable UK cities, and they are firmly positioned at the premium end of the local rental market. This four-bedroom, two-bathroom example at £2,000 pcm offers 140 sq metres of living space alongside a private garden — features that are particularly prized by families seeking the space and privacy that apartments and terraced homes simply cannot provide. York''s average house price for detached properties stands at over £517,000, underlining the scale of investment and quality typically associated with this property type, and the rental price reflects this premium positioning. The semi-furnished specification provides a practical baseline of key fittings while leaving ample room for personalisation, suiting families relocating to York who wish to bring cherished belongings. Detached property rents in York rose 5.0% in the year to February 2026, demonstrating that demand for larger family homes remains healthy and well-supported across the city''s strong employment and school catchment landscape.'),
('Bungalow', 'York', 1350, 2, 1, 75, 'Furnished', 'A cosy bungalow in York offering two bedrooms and a bright living space. Ideal for relaxed living.', 1, '2026-01-05', 'Bungalows are a rare and distinctive property type in York''s rental market, where the city''s predominantly Victorian and Edwardian terraced housing stock means single-storey homes represent a genuine scarcity. This two-bedroom furnished example at £1,350 pcm offers something that the majority of York''s rental listings cannot: step-free, accessible living with no stairs, making it especially appealing to older tenants, those with mobility considerations, or anyone simply seeking a calmer and more manageable home environment. The furnished specification removes any upfront costs and allows tenants to move in immediately, a practical advantage that broadens the appeal to a wide range of prospective renters. At 75 sq metres the layout is well-proportioned for two bedrooms, and the bright living space creates a welcoming atmosphere. York''s rental market saw rents rise 5.7% in the year to February 2026, and the scarcity of bungalows relative to demand means this type of property consistently attracts strong interest, short void periods, and reliable long-term tenancies.'),
('Semi-Detached', 'York', 1500, 3, 2, 100, 'Unfurnished', 'A semi-detached home in York offering three bedrooms and spacious living areas. Conveniently located near amenities.', 2, '2026-01-01', 'Semi-detached homes account for 27% of York''s housing stock and are among the most consistently sought-after property types in the city, particularly among families and professional sharers who value the balance of space, privacy, and affordability they offer. At £1,500 pcm, this three-bedroom, two-bathroom property sits well above York''s three-bedroom average of £1,246, reflecting its generous 100 sq metre footprint and the practical advantages of two bathrooms — a feature that significantly improves daily life for multiple occupants. Unfurnished, it is ideally suited to longer-term tenants who wish to bring their own belongings and settle in comfortably, a profile that typically produces stable, low-turnover tenancies. Convenient access to local amenities is a key draw, and York''s exceptional connectivity — with direct rail links to Leeds, Manchester, and London — makes it an increasingly popular base for professionals commuting across the North. Semi-detached property values in York have shown steady appreciation, and with rents across the city rising 5.7% in the year to February 2026, this well-priced family home represents a strong and reliable rental proposition.');
